function defaultPersonalGoals(){ return {steps:{enabled:!!state?.activitySettings?.dailyStepTarget?.enabled,target:8000,direction:'minimum',front:!!state?.activitySettings?.dailyStepTarget?.enabled},socialMediaTime:{enabled:!!state?.activitySettings?.socialMediaFree?.enabled,target:30,direction:'maximum',front:!!state?.activitySettings?.socialMediaFree?.enabled},meditationMinutes:{enabled:!!state?.activitySettings?.meditation?.enabled,target:10,direction:'minimum',front:!!state?.activitySettings?.meditation?.enabled},breathingActivities:{enabled:!!state?.activitySettings?.breathing?.enabled,target:1,direction:'minimum',front:!!state?.activitySettings?.breathing?.enabled}}; }
function personalGoalDefaultFor(id,m){ const base=defaultPersonalGoals()[id] || {enabled:false,target:'',direction:m.goalDirection,front:false}; return {...base,direction:base.direction||m.goalDirection}; }
function normalizePersonalGoals(){ state.personalGoals={...(state.personalGoals||{})}; Object.entries(personalMetrics).forEach(([id,m])=>{ const g=state.personalGoals[id] ||= personalGoalDefaultFor(id,m); if(g.direction==='atLeast') g.direction='minimum'; if(g.direction==='atMost') g.direction='maximum'; g.direction=g.direction||m.goalDirection; if(g.enabled==null) g.enabled=false; if(g.front==null) g.front=!!g.enabled; if(m.activity && state.activitySettings?.[m.activity]?.enabled && !g.target) g.target=goalFor(m.activity)||g.target; }); }
function migratePersonalGoalActivityState(){ const rawGoals=state.personalGoals||{}; normalizePersonalGoals(); Object.entries(personalMetrics).forEach(([id,m])=>{ if(!m.activity || !state.activitySettings?.[m.activity]) return; const g=state.personalGoals[id], raw=rawGoals[id]||{}; const activityEnabled=!!state.activitySettings[m.activity].enabled; const goalHasChoice=Object.prototype.hasOwnProperty.call(rawGoals,id) && (typeof raw.enabled==='boolean'||typeof raw.front==='boolean'); const goalEnabled=!!(raw.enabled||raw.front); const enabled=goalHasChoice && goalEnabled!==activityEnabled ? goalEnabled : activityEnabled; g.enabled=enabled; g.front=enabled; state.activitySettings[m.activity].enabled=enabled; if(enabled && !g.target) g.target=goalFor(m.activity)||g.target; }); persist(); }
function personalMetricEnabled(id,m=personalMetrics[id],g=state.personalGoals[id]){ return m?.activity && state.activitySettings?.[m.activity] ? !!state.activitySettings[m.activity].enabled : !!g?.enabled; }
function setPersonalMetricEnabled(metricId, enabled){ const m=personalMetrics[metricId]; const g=state.personalGoals[metricId] ||= personalGoalDefaultFor(metricId,m||{}); g.enabled=!!enabled; g.front=!!enabled; if(m?.activity && state.activitySettings?.[m.activity]) state.activitySettings[m.activity].enabled=!!enabled; persist(); }
function syncActivityPersonalGoals(activityId, enabled){ Object.entries(personalMetrics).forEach(([id,m])=>{ if(m.activity===activityId){ const g=state.personalGoals[id] ||= personalGoalDefaultFor(id,m); g.enabled=!!enabled; g.front=!!enabled; } }); }
function dataSourceStatus(){ return {manual:'connected',healthConnect:'notConnected',screenTime:'notAvailable',wearable:'notConnected'}; }
function sourceLabel(source, value){ if(value?.source==='manual') return 'Manuelt registreret'; const ds=dataSourceStatus(); if(source==='manual') return 'Manuel'; if(source==='health') return ds.healthConnect==='connected'?'Automatisk':'Health Connect ikke forbundet'; if(source==='screenTime') return 'Automatisk registrering kommer senere'; if(source==='wearable') return 'Wearable ikke forbundet'; if(source==='manualOrWearable') return value?.available?'Manuelt registreret':'Manuel / wearable ikke forbundet'; return 'Ikke forbundet'; }
function personalMetricValue(metricId,date=todayKey()){ const m=personalMetrics[metricId]; if(!m) return {available:false,value:null,source:null}; const logVal=(activity)=>entries(date).filter(e=>e.activity===activity).reduce((s,e)=>s+num(e.value??e.hours),0); let v=null; if(metricId==='steps') v=logVal('dailyStepTarget') || logVal('mostSteps'); else if(metricId==='socialMediaTime') v=logVal('socialMediaFree'); else if(metricId==='meditationMinutes') v=logVal('meditation'); else if(metricId==='breathingActivities') v=logVal('breathing'); else if(metricId==='strengthSets') v=logVal('strength'); else if(metricId==='distance') v=logVal('running')+logVal('cycling'); else if(metricId==='bedtime') v=entries(date).filter(e=>e.activity==='bedtime').slice(-1)[0]?.value; else if(metricId==='sleepDuration') v=entries(date).filter(e=>e.activity==='sleepDuration').slice(-1)[0]?.hours; else if(m.activity) v=periodValue(m.activity,date); return v?{available:true,value:v,source:'manual'}:{available:false,value:null,source:null}; }
function personalGoalStatus(metricId,value,goalConfig={}){ const m=personalMetrics[metricId]||{}, direction=goalConfig.direction||m.goalDirection, target=num(goalConfig.target), min=num(goalConfig.minimum), max=num(goalConfig.maximum); if(!value?.available) return {available:false,reached:false,progressPercent:0,label:'Ingen data',state:'missing'}; const v=num(value.value); if(direction==='informational') return {available:true,reached:null,progressPercent:0,label:'Til information',state:'info'}; if(direction==='maximum'||direction==='timeBefore'){ const reached=v<=target, over=Math.max(0,v-target); return {available:true,reached,progressPercent:target?clamp((target-v)/target*100,0,100):0,label:reached?'Mål nået':`Lidt over målet i dag`,state:reached?'reached':'warning',detail:reached?`${fmt(Math.max(0,target-v))} ${m.unit} tilbage`:`${fmt(over)} ${m.unit} over målet`}; } if(direction==='range'){ const reached=v>=min&&v<=max; return {available:true,reached,progressPercent:reached?100:clamp(v/Math.max(1,min||target)*100,0,100),label:reached?'Mål nået':'Ikke nået endnu',state:reached?'reached':'pending'}; } const reached=v>=target; return {available:true,reached,progressPercent:clamp(v/Math.max(1,target)*100,0,100),label:reached?'Mål nået':'Ikke nået endnu',state:reached?'reached':'pending'}; }
function personalGoalValueText(id,value,g){ const m=personalMetrics[id], v=value.available?fmt(value.value):'Ingen data'; if(!value.available) return 'Ingen data'; if((g.direction||m.goalDirection)==='atMost') g.direction='maximum'; if((g.direction||m.goalDirection)==='maximum'||(g.direction||m.goalDirection)==='timeBefore') return `${v} af højst ${fmt(g.target)} ${m.unit}`; if((g.direction||m.goalDirection)==='range') return `${v} ${m.unit} · mål ${fmt(g.minimum||0)}–${fmt(g.maximum||g.target)} ${m.unit}`; if((g.direction||m.goalDirection)==='informational') return `${v} ${m.unit}`; return `${v} af ${fmt(g.target)} ${m.unit}`; }
function compactDecimal(value, decimals=1){ const n=Number(value)||0; return n.toLocaleString('da-DK',{maximumFractionDigits:decimals,minimumFractionDigits:Number.isInteger(n)?0:decimals}); }
function personalMetricDisplayValue(id, value) {
  if(!value?.available) return '';
  const v=Number(value.value)||0;
  if(id==='steps') return Math.round(v).toLocaleString('da-DK');
  if(['socialMediaTime','totalScreenTime','activeMinutes','meditationMinutes'].includes(id)) return `${Math.round(v).toLocaleString('da-DK')} min`;
  if(id==='sleepDuration') return `${compactDecimal(v,1)} t`;
  if(id==='bedtime') return String(value.value).replace(':','.');
  if(id==='distance') return `${compactDecimal(v,1)} km`;
  if(id==='strengthSets') return `${Math.round(v).toLocaleString('da-DK')} sæt`;
  if(id==='restingHeartRate') return `${Math.round(v).toLocaleString('da-DK')} bpm`;
  if(id==='heartRateVariability') return `${Math.round(v).toLocaleString('da-DK')} ms`;
  const unit=personalMetrics[id]?.unit;
  return unit ? `${compactDecimal(v,1)} ${unit}` : compactDecimal(v,1);
}
function personalGoalStatusIcon(status, direction){
  if(direction==='informational') return '';
  if(status.state==='warning') return '<span class="personal-goal-state warning" aria-label="Over dit ønskede maksimum" role="img">!</span>';
  if(status.reached===true) return '<span class="personal-goal-state reached" aria-label="Mål nået" role="img">✓</span>';
  return '<span class="personal-goal-state pending" aria-label="Mål ikke nået endnu" role="img">○</span>';
}
function renderPersonalGoals(){ const box=$('#personal-goal-list'); if(!box) return; normalizePersonalGoals(); if(!activeActivityIds().length) state.personalGoals={}; const rows=Object.entries(personalMetrics).map(([id,m],index)=>{ const raw=state.personalGoals[id]||{}, g={...raw,enabled:personalMetricEnabled(id,m,raw),front:personalMetricEnabled(id,m,raw)}, value=personalMetricValue(id), status=personalGoalStatus(id,value,g); return {id,m,g,value,status,index,rank:(g.enabled?0:1)}; }).filter(r=>r.g.enabled&&r.value.available===true).sort((a,b)=>a.rank-b.rank||a.index-b.index); const visible=showAllPersonalGoals?rows:rows.slice(0,6); const reached=rows.filter(r=>r.g.enabled&&r.status.reached===true).length, total=rows.filter(r=>r.g.enabled&&(r.g.direction||r.m.goalDirection)!=='informational').length; const summary=$('#today-goal-summary'); if(summary) summary.textContent=total?`${reached} af ${total}`:''; box.innerHTML=visible.map(r=>{ const direction=r.g.direction||r.m.goalDirection; return `<div class="personal-goal-row ${r.status.state}"><div class="personal-goal-main"><span class="personal-goal-icon" aria-hidden="true">${r.m.icon}</span><strong>${r.m.title}</strong></div><div class="personal-goal-result"><span class="personal-goal-value">${personalMetricDisplayValue(r.id,r.value)}</span>${personalGoalStatusIcon(r.status,direction)}</div></div>`; }).join('') || '<p class="personal-goals-empty">Ingen registreringer endnu i dag.</p>'; const more=$('#show-all-personal-goals'); if(more){ more.hidden=rows.length<=6; more.textContent=showAllPersonalGoals?'Vis færre':'Vis alle'; } }


