function normalizeCompetitionType(type){ return type==='others'?'versus':(competitionTypes[type]?.id||'self'); }
function competitionTypeLabel(type){ return competitionTypes[normalizeCompetitionType(type)].title; }
function isCoopCompetition(c){ return normalizeCompetitionType(c?.type)==='coop'; }
