function clearCompetitionDraft(){ localStorage.removeItem(KEYS.competitionDraft); }
const streakDefaults = { bedtime:5, bedtimeConsistency:5, sleepDuration:6, wakeTime:5, sleepGoalNights:5, meditation:5, breathing:5, mostSteps:5, dailyStepTarget:5, steps:5, screenFreeBeforeBed:5, socialMediaFree:5, strength:3, running:3, cycling:3 };
const focusActivities = ['bedtime','meditation','breathing'];
const $ = s => document.querySelector(s); const $$ = s => Array.from(document.querySelectorAll(s));
function consumeInteraction(e){ e?.preventDefault?.(); e?.stopPropagation?.(); }
const todayKey = () => (window.__oneUpNow ? window.__oneUpNow() : new Date()).toISOString().slice(0,10);
const day = (offset=0, base=todayKey()) => { const d=new Date(`${base}T12:00:00Z`); d.setUTCDate(d.getUTCDate()+offset); return d.toISOString().slice(0,10); };
const num = v => Math.max(0, Number(v)||0); const clamp=(v,min=0,max=100)=>Math.max(min,Math.min(max,v)); const fmt = v => Math.round(v).toLocaleString('da-DK');
function splitDuration(totalMinutes) { const value = Math.max(0, Number(totalMinutes) || 0); return { hours: Math.floor(value / 60), minutes: value % 60 }; }
function combineDuration(hours, minutes) { return Math.max(0, (Number(hours) || 0) * 60 + (Number(minutes) || 0)); }
function formatDuration(totalMinutes) { const { hours, minutes } = splitDuration(totalMinutes); if (hours && minutes) return `${hours} t. ${minutes} min.`; if (hours) return `${hours} t.`; return `${minutes} min.`; }
const durationActivityIds = new Set(['screenFreeBeforeBed','meditation','swimming','yoga','mobility','trainingTime','activeMinutesWearable','socialMediaFree','sleepDuration','timeInBed']);
const durationPersonalMetricIds = new Set(['socialMediaTime','totalScreenTime','activeMinutes','meditationMinutes','sleepDuration']);
function isDurationActivity(id){ return durationActivityIds.has(normalizeActivityId(id)); }
