function ageFromBirthDate(birthDate, referenceDate = new Date()){
  if(!/^\d{4}-\d{2}-\d{2}$/.test(birthDate||'')) return null;
  const [y,m,d]=birthDate.split('-').map(Number), ref=new Date(referenceDate);
  let age=ref.getFullYear()-y;
  const hasBirthdayPassed=(ref.getMonth()+1>m)||((ref.getMonth()+1)===m&&ref.getDate()>=d);
  return hasBirthdayPassed ? age : age-1;
}
