function effectiveDate(e){ if(e.activity!=='sleep'&&e.activity!=='sleepDuration') return e.date; if(e.sleepDate) return e.sleepDate; if(e.end && e.start && e.end < e.start) return e.date; return e.date; }
function entries(date=todayKey(), id=null){ return state.log.filter(e=>effectiveDate(e)===date && (!id || e.activity===id)); }
function valueFor(id,date=todayKey()){ id=normalizeActivityId(id); const es=entries(date,id); if(id==='mostSteps'||id==='dailyStepTarget') return es.at(-1)?.value || entries(date,'steps').at(-1)?.value || state.history[date]?.steps || 0; if(id==='sleepDuration') return es.reduce((s,e)=>s+num(e.hours ?? e.value),0); return es.reduce((s,e)=>s+num(e.value),0); }
function goalFor(id){ if(id==='steps') id='dailyStepTarget'; else id=normalizeActivityId(id); if(isSessionGoalActivity(id)) return targetCountFor(id); return num(state.activitySettings[id]?.goal ?? activityMeta(id)?.goal); }
function dailyRequirementFor(id){ if(id==='steps') id='dailyStepTarget'; else id=normalizeActivityId(id); return num(state.activitySettings[id]?.dailyRequirement ?? goalFor(id)); }
function periodValue(id,date=todayKey()){ id=normalizeActivityId(id); if(isSessionGoalActivity(id) && goalPeriodFor(id)==='weekly') return weekValueFor(id,date); if((activityMeta(id).period||'day')==='day') return valueFor(id,date); return weekValueFor(id,date); }
function activityPercent(id,date=todayKey()){ id=normalizeActivityId(id); const g=goalFor(id); if(id==='mostSteps') return Math.min(100, valueFor(id,date)/Math.max(1,goalFor('dailyStepTarget')||8000)*100); if(!g) return 0; if(id==='socialMediaFree') return scoreLessIsBetter(periodValue(id,date),g,null); return Math.min(100, periodValue(id,date)/g*100); }
function pointsForEntry(e){ const g=goalFor(e.activity); if(e.activity==='steps'||e.activity==='mostSteps'||e.activity==='dailyStepTarget') return Math.floor(num(e.value)/100); if(e.activity==='breathing') return num(e.value)*5; if(e.activity==='meditation') return Math.min(30,num(e.value)); if(e.activity==='strength') return 20; if(e.activity==='running') return Math.min(60,num(e.value))*2; if(e.activity==='cycling') return Math.min(60,num(e.value)); if(e.activity==='sleep'||e.activity==='sleepDuration') return num(e.hours ?? e.value)>=g?20:0; if(e.activity==='screenFreeBeforeBed') return num(e.value)>=g?15:0; if(e.activity==='socialMediaFree') return (e.mode==='usage'?num(e.value)<=g:num(e.value)>=g)?15:0; return 0; }
