function withinTime(value,target,tol){ const diff=Math.abs(((minutes(value)-minutes(target)+720+1440)%1440)-720); return diff<=num(tol); }
function sleepMet(date,id='sleepDuration'){ const s=state.activitySettings[id]||state.activitySettings.sleepDuration, es=entries(date,id), hours=id==='sleep'?es.reduce((sum,e)=>sum+num(e.hours ?? e.value),0):valueFor(id,date); if(!es.length) return false; const checks=[]; if(s.sleepCriteria?.duration) checks.push(hours+num(s.sleepMinTolerance||0)>=num(s.sleepMinHours||dailyRequirementFor('sleep'))); if(s.sleepCriteria?.interval) checks.push(hours>=num(s.sleepMinInterval||7)&&hours<=num(s.sleepMaxInterval||9)); if(s.sleepCriteria?.bedtime) checks.push(es.some(e=>withinTime(e.start,s.bedtimeTarget,s.bedtimeTolerance))); if(s.sleepCriteria?.wake) checks.push(es.some(e=>withinTime(e.end,s.wakeTarget,s.wakeTolerance))); if(s.sleepCriteria?.screenfree) checks.push(requirementMet('screenFreeBeforeBed',date)); return checks.length?checks.every(Boolean):hours>=dailyRequirementFor('sleep'); }
function requirementMet(id,date=todayKey()){ const legacySleep=id==='sleep'; if(!legacySleep) id=normalizeActivityId(id); if(!state.activitySettings[id]?.streakEnabled) return false; if(id==='sleepDuration'||legacySleep) return sleepMet(date, legacySleep?'sleep':'sleepDuration'); if(id==='socialMediaFree') { const es=entries(date,id); if(es.at(-1)?.mode==='usage') return num(es.at(-1).value)<=dailyRequirementFor(id); } if(isSessionGoalActivity(id) && goalPeriodFor(id)==='weekly') return weekValueFor(id,date)>=targetCountFor(id); return valueFor(id,date)>=dailyRequirementFor(id); }

