let firebaseApi=null, cloudSyncTimer=null, cloudSyncInProgress=false, authReady=false;
function getInstallId(){ let id=localStorage.getItem(KEYS.installId); if(!id){ id=`oneup-${Date.now()}-${Math.random().toString(16).slice(2)}`; localStorage.setItem(KEYS.installId,id); } return id; }
function localSnapshot(){ return {points:state.points,history:state.history,profile:state.profile,settings:state.settings,activitySettings:state.activitySettings,log:state.log,streakData:state.streakData,competitions:state.competitions,competitionUi:state.competitionUi,personalGoals:state.personalGoals,updatedAt:new Date().toISOString(),schemaVersion:DATA_VERSION}; }
function hasLocalOneUpData(){ return !!(state.log?.length || Object.keys(state.history||{}).length>1 || state.points || Object.keys(state.profile||{}).length || state.competitions?.length); }
function validateSnapshot(d){ return d && typeof d==='object' && Array.isArray(d.log||[]) && typeof (d.history||{})==='object'; }
function mergeById(local=[],cloud=[]){ const m=new Map(); [...cloud,...local].forEach(x=>{ if(!x) return; const id=x.id || `${x.date}-${x.activity}-${x.value??x.hours??''}`; const prev=m.get(id); m.set(id, !prev || String(x.updatedAt||x.date||'')>=String(prev.updatedAt||prev.date||'') ? {...prev,...x,id} : prev); }); return [...m.values()]; }
function mergeCloudSnapshot(cloud){ if(!validateSnapshot(cloud)) return false; const newerSettings=String(cloud.updatedAt||'')>String(localSnapshot().updatedAt||''); state.log=mergeById(state.log, cloud.log); state.competitions=mergeById(state.competitions, cloud.competitions); state.history={...(cloud.history||{}),...(state.history||{})}; if(newerSettings){ state.profile={...state.profile,...(cloud.profile||{})}; state.settings={...state.settings,...(cloud.settings||{})}; state.activitySettings={...state.activitySettings,...(cloud.activitySettings||{})}; state.personalGoals={...state.personalGoals,...(cloud.personalGoals||{})}; }
  recalcSilently(); persist(); return true; }
async function loadFirebaseApi(){ if(firebaseApi) return firebaseApi; if(typeof window==='undefined') return null; const [appMod,authMod,firestoreMod]=await Promise.all([import(`https://www.gstatic.com/firebasejs/${FIREBASE_SDK_VERSION}/firebase-app.js`),import(`https://www.gstatic.com/firebasejs/${FIREBASE_SDK_VERSION}/firebase-auth.js`),import(`https://www.gstatic.com/firebasejs/${FIREBASE_SDK_VERSION}/firebase-firestore.js`)]); const app=appMod.getApps().length?appMod.getApp():appMod.initializeApp(firebaseConfig); firebaseApi={...authMod,...firestoreMod,app,auth:authMod.getAuth(app),db:firestoreMod.getFirestore(app)}; return firebaseApi; }
async function initFirebaseAuth(){ try{ const fb=await loadFirebaseApi(); if(!fb) return; fb.onAuthStateChanged(fb.auth, async user=>{ state.auth={...(state.auth||{}),mode:user?'account':'guest',user,syncStatus:user?'Synkroniserer…':'Offline'}; render(); if(user){ await ensureUserDocument(user); await maybePromptMigration(user); await pullCloudData(user); scheduleCloudSync(250); } }); authReady=true; }catch(e){ state.auth={...(state.auth||{}),syncStatus:'Offline'}; renderAccountSummary(); } }
function firebaseErrorMessage(error){ const code=error?.code||''; if(code.includes('email-already-in-use')) return 'E-mailadressen er allerede i brug.'; if(code.includes('wrong-password')||code.includes('invalid-credential')||code.includes('user-not-found')) return 'E-mail eller adgangskode er forkert.'; if(code.includes('weak-password')) return 'Adgangskoden skal være mindst 6 tegn.'; if(code.includes('invalid-email')) return 'Indtast en gyldig e-mailadresse.'; if(code.includes('requires-recent-login')) return 'Af sikkerhedshensyn skal du logge ind igen, før kontoen kan slettes.'; return 'Der kunne ikke oprettes forbindelse. Prøv igen.'; }
async function ensureUserDocument(user){ const fb=await loadFirebaseApi(); if(!user?.uid) return; await fb.setDoc(fb.doc(fb.db,'users',user.uid),{displayName:user.displayName||'',email:user.email||'',updatedAt:fb.serverTimestamp(),lastSyncedAt:fb.serverTimestamp(),schemaVersion:DATA_VERSION,emailVerified:!!user.emailVerified},{merge:true}); }
async function pullCloudData(user=state.auth?.user){ const fb=await loadFirebaseApi(); if(!user?.uid) return; try{ const snap=await fb.getDoc(fb.doc(fb.db,'users',user.uid,'appData','main')); if(snap.exists()) mergeCloudSnapshot(snap.data()?.data||{}); state.auth.syncStatus='Synkroniseret'; state.auth.lastSyncedAt=new Date().toISOString(); renderAccountSummary(); }catch{ state.auth.syncStatus=navigator.onLine===false?'Offline':'Synkronisering mislykkedes'; renderAccountSummary(); } }
function scheduleCloudSync(delay=1200){ if(!state?.auth?.user?.uid || !firebaseApi) return; clearTimeout(cloudSyncTimer); state.auth.syncStatus=navigator.onLine===false?'Offline':'Synkroniserer…'; cloudSyncTimer=setTimeout(syncToCloud,delay); renderAccountSummary(); }
async function syncToCloud(){ if(cloudSyncInProgress || !state.auth?.user?.uid) return; cloudSyncInProgress=true; try{ const fb=await loadFirebaseApi(), uid=state.auth.user.uid; await fb.setDoc(fb.doc(fb.db,'users',uid,'appData','main'),{data:localSnapshot(),updatedAt:fb.serverTimestamp(),lastSyncedAt:fb.serverTimestamp(),schemaVersion:DATA_VERSION},{merge:true}); await ensureUserDocument(state.auth.user); state.auth.syncStatus='Synkroniseret'; state.auth.lastSyncedAt=new Date().toISOString(); }catch{ state.auth.syncStatus=navigator.onLine===false?'Offline':'Synkronisering mislykkedes'; setTimeout(()=>scheduleCloudSync(5000),5000); } finally{ cloudSyncInProgress=false; renderAccountSummary(); } }
async function maybePromptMigration(user){ const migration=read(KEYS.migration,{}); if(migration[user.uid]?.localMigrationCompleted || !hasLocalOneUpData()) return; openMigrationDialog(user); }
function openMigrationDialog(user){ if($('#migration-dialog')) return; document.body.insertAdjacentHTML('beforeend',`<div id="migration-dialog" class="modal"><div class="modal-card"><h2>Du har fremskridt gemt på denne enhed.</h2><p>Vil du gemme dem på din konto?</p><div class="button-row"><button data-migrate-cloud>Gem på min konto</button><button class="secondary" data-keep-cloud>Behold cloud-data</button><button class="secondary" data-cancel-migration>Annuller</button></div></div></div>`); const d=$('#migration-dialog'); d.querySelector('[data-cancel-migration]').onclick=()=>d.remove(); d.querySelector('[data-keep-cloud]').onclick=()=>{ const m=read(KEYS.migration,{}); m[user.uid]={localMigrationCompleted:true,keptCloudData:true,installId:getInstallId(),date:new Date().toISOString()}; save(KEYS.migration,m); d.remove(); pullCloudData(user); }; d.querySelector('[data-migrate-cloud]').onclick=async()=>{ save(KEYS.localBackup,localSnapshot()); if(!validateSnapshot(localSnapshot())){ showToast('Lokale data kunne ikke valideres.'); return; } await syncToCloud(); const m=read(KEYS.migration,{}); m[user.uid]={localMigrationCompleted:true,installId:getInstallId(),date:new Date().toISOString()}; save(KEYS.migration,m); d.remove(); showToast('Dine lokale fremskridt er gemt på kontoen.'); }; }
function authStatusHtml(){ const u=state.auth?.user; if(!u) return `<p class="muted">Kun gemt på denne enhed</p><p>Gem og synkronisér dine fremskridt mellem enheder.</p><div class="button-row"><button data-auth-open="signup">Opret gratis konto</button><button class="secondary" data-auth-open="login">Log ind</button><button class="secondary" data-auth-guest>Fortsæt som gæst</button></div>`; return `<p><b>${escapeHtml(u.displayName||state.profile.name||'OneUp-bruger')}</b><br>${escapeHtml(u.email||'')}</p><p class="muted">E-mail: ${u.emailVerified?'bekræftet':'ikke bekræftet'} · ${state.auth.syncStatus||'Synkroniseret'}</p>`; }
function renderAccountSummary(){ const el=$('#account-summary'); if(el) el.innerHTML=''; }
function openAuthDialog(mode='login'){ $('#auth-dialog')?.remove(); const signup=mode==='signup', reset=mode==='reset'; document.body.insertAdjacentHTML('beforeend',`<div id="auth-dialog" class="modal"><div class="modal-card auth-card"><button class="secondary" data-auth-close>← Luk</button><h2>${signup?'Opret gratis konto':reset?'Glemt adgangskode':'Log ind'}</h2><p class="muted">Gem og synkronisér dine fremskridt mellem enheder</p><form id="auth-form">${signup?'<label class="field">Navn<input name="name" autocomplete="name"></label>':''}<label class="field">E-mail<input name="email" type="email" autocomplete="email"></label>${reset?'':'<label class="field">Adgangskode<input name="password" type="password" autocomplete="current-password"></label>'}${signup?'<label class="field">Gentag adgangskode<input name="repeat" type="password"></label>':''}<p class="error" id="auth-error"></p><button type="submit">${signup?'Opret konto':reset?'Send nulstillingsmail':'Log ind'}</button></form>${!reset?'<button class="secondary" data-auth-open="reset">Glemt adgangskode</button>':''}</div></div>`); const d=$('#auth-dialog'); d.querySelector('[data-auth-close]').onclick=()=>d.remove(); d.querySelectorAll('[data-auth-open]').forEach(b=>b.onclick=()=>openAuthDialog(b.dataset.authOpen)); d.querySelector('#auth-form').onsubmit=async e=>{ e.preventDefault(); const fd=new FormData(e.target), email=String(fd.get('email')||'').trim(), password=String(fd.get('password')||''), err=$('#auth-error'); if(!email.includes('@')){err.textContent='Indtast en gyldig e-mailadresse.';return;} if(!reset && password.length<6){err.textContent='Adgangskoden skal være mindst 6 tegn.';return;} if(signup && password!==String(fd.get('repeat')||'')){err.textContent='Adgangskoderne er ikke ens.';return;} try{ const fb=await loadFirebaseApi(); if(signup){ const cred=await fb.createUserWithEmailAndPassword(fb.auth,email,password); await fb.updateProfile(cred.user,{displayName:String(fd.get('name')||'').trim()}); await fb.sendEmailVerification(cred.user); showToast('Konto oprettet. Vi har sendt en bekræftelsesmail.'); } else if(reset){ await fb.sendPasswordResetEmail(fb.auth,email); showToast('Hvis adressen er registreret, er der sendt en mail med et link til at vælge en ny adgangskode.'); } else await fb.signInWithEmailAndPassword(fb.auth,email,password); d.remove(); }catch(ex){ err.textContent=firebaseErrorMessage(ex); } }; }
async function resendVerification(){ try{ const fb=await loadFirebaseApi(); if(fb.auth.currentUser){ await fb.sendEmailVerification(fb.auth.currentUser); showToast('Bekræftelsesmail sendt igen.'); }}catch(e){ showToast(firebaseErrorMessage(e)); } }
